		if _, deprecated := deprecatedPersonas[p.Name]; deprecated {
			displayName = p.Name + " (deprecated)"
			deprecatedSeen = append(deprecatedSeen, p.Name)
		}
		source := p.Source
		if source == "" {
			source = "library"
		}
		_, _ = fmt.Fprintf(w, "%s\t%s\t%s\t%s\n", displayName, source, roleStr, p.Description)
	}

	_ = w.Flush()

